1. using System.Collections.Concurrent;
2. 
3. namespace TaskManager;
4. 
5. public sealed class TaskService
6. {
7.     private readonly ConcurrentDictionary<int, TaskItem> _tasks = new();
8.     private readonly ITaskNotifier _notifier;
9.     private int _nextId;
10. 
11.     public TaskService(ITaskNotifier notifier)
12.     {
13.         _notifier = notifier ?? throw new ArgumentNullException(nameof(notifier));
14.     }
15. 
16.     public TaskItem CreateTask(string title, string assignedTo, TaskPriority priority)
17.     {
18.         if (string.IsNullOrWhiteSpace(title))
19.             throw new ArgumentException("Title is required.", nameof(title));
20. 
21.         if (string.IsNullOrWhiteSpace(assignedTo))
22.             throw new ArgumentException("AssignedTo is required.", nameof(assignedTo));
23. 
24.         var id = Interlocked.Increment(ref _nextId);
25.         var task = new TaskItem
26.         {
27.             Id = id,
28.             Title = title,
29.             AssignedTo = assignedTo,
30.             Priority = priority,
31.             Status = TaskItemStatus.Open
32.         };
33. 
34.         _tasks[id] = task;
35.         _notifier.NotifyCreated(task);
36.         return task;
37.     }
38. 
39.     public TaskItem? GetById(int id) => _tasks.GetValueOrDefault(id);
40. 
41.     public IReadOnlyList<TaskItem> GetByAssignee(string assignedTo)
42.     {
43.         return _tasks.Values
44.             .Where(t => t.AssignedTo.Equals(assignedTo, StringComparison.OrdinalIgnoreCase))
45.             .ToList();
46.     }
47. 
48.     public void DeleteTask(int id, string requestedBy)
49.     {
50.         if (!_tasks.TryGetValue(id, out var task))
51.             throw new InvalidOperationException($"Task {id} not found.");
52. 
53.         // Only the assignee or an admin can delete
54.         if (!task.AssignedTo.Equals(requestedBy, StringComparison.OrdinalIgnoreCase)
55.             && !requestedBy.Equals("admin", StringComparison.OrdinalIgnoreCase))
56.         {
57.             throw new UnauthorizedAccessException("Only the assignee or admin can delete a task.");
58.         }
59. 
60.         task.Status = TaskItemStatus.Deleted;
